let time_now = Date.now();

if ($input.first().json.files != null) {
  let file_data =  $input.first().binary.data0;
  let file_name = `${time_now}_${$input.first().json.sessionId}_${file_data.fileName}`;
  return {
    timestamp: time_now,
    have_file: true,
    file: file_data,
    file_name,
    ...$input.first().json,
  };
} else {
  return {
    timestamp: time_now,
    file_name: "",
    have_file: false,
    ...$input.first().json
  }
}

const parts = $json?.content?.parts || [];

const markdown = parts
  .map(p => p?.text || "")
  .join("\n")
  .trim();

// Agent chỉ cần 1 field text
return [
  {
    json: {
      text: markdown
    }
  }
];

const files = $("upload_image_res_gen").all() || [];

const markdown = files
  .filter(file => file.json.mimeType?.startsWith("image/"))
  .map(file => {
    const thumb = file.json.thumbnailLink;
    const download = file.json.webViewLink;
    const name = file.json.name;

    return `
### Ảnh sau khi tạo

[![${name}](${thumb})](${download})

[⬇ Download ảnh](${download})
`;
  })
  .join("\n");

return [
  {
    json: {
      text: markdown.trim()
    }
  }
];

