const files = $("upload_image_res_edit").all() || [];

const markdown = files
  .filter(file => file.json.mimeType?.startsWith("image/"))
  .map(file => {
    const thumb = file.json.thumbnailLink;
    const download = file.json.webViewLink;
    const name = file.json.name;

    return `
### Ảnh sau khi tạo

[![${name}](${thumb})](${download})

[⬇ Download ảnh](${download})
`;
  })
  .join("\n");

return [
  {
    json: {
      text: markdown.trim()
    }
  }
];

return [
  {
    json: {
      text: "Yêu cầu hỏi các nội dung liên quan đến: phân tích ảnh, tạo ảnh và sửa ảnh"
    }
  }
];

const data = $("Prepare data req to model edit image").first().json;

// 1. Ưu tiên current_chat_input
if (data?.current_chat_input?.have_img && data.current_chat_input.data_field) {
  return {
    json: {
      data_field: data.current_chat_input.data_field,
    },
    binary: $("Prepare data req to model edit image").first().binary
  };
}

// 2. Nếu không có thì lấy previous_chat_input đầu tiên hợp lệ
if (Array.isArray(data?.previous_chat_input)) {
  const found = data.previous_chat_input.find(
    item => item?.have_img && item.data_field
  );

  if (found) {
    return {
      json: {
        data_field: found.data_field,
      },
      binary: $("Prepare data req to model edit image").first().binary
    };
  }
}

// 3. Không có thì trả null
return {
  json: {
    data_field: null,
  },
  binary: $("Prepare data req to model edit image").first().binary
};

return [
  {
    json: {
      text: "Không tìm thấy dữ liệu, vui lòng thêm ảnh mới để tiếp tục"
    }
  }
];
